ANY_MONEY_RX = re.compile(r"([\d\s]+(?:[.,]\d{2}))\s*(?:вӮҪ|RUB|Р В Р’В Р вҖҷР’В Р В РІРӮв„ўР вҖҷР’В Р В Р’В Р РҶР вҖҡРІвҖһСһР В РІРӮв„ўР вҖҷР’В Р В Р’В Р вҖҷР’В Р В РІРӮв„ўР вҖҷР’В Р В Р’В Р вҖҷР’В Р В Р вҖ Р РҶР вҖҡРЎв„ўР вҖҷР’В¬Р В Р’В Р вҖҷР’В Р В РІРӮв„ўР вҖҷР’В Р В Р’В Р В РІРӮВ Р В Р’В Р РҶР вҖҡРЎв„ўР В РІРӮв„ўР вҖҷР’Вҳ)", re.I)
CARD_TAIL_RX = re.compile(r"^\d{4}$")
